using Microsoft.AspNetCore.Mvc;
using System.Data.SqlClient;

namespace MyApi.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UserController : ControllerBase
    {
        [HttpGet]
        public IActionResult SearchUsers([FromQuery] string email)
        {
            if (string.IsNullOrEmpty(email))
                return BadRequest("Email is required");

            try
            {
                using (SqlConnection connection = new SqlConnection("Server=myserver;Database=mydatabase;User Id=myuser;Password=mypassword;"))
                {
                    connection.Open();

                    SqlCommand command = new SqlCommand("SELECT * FROM Users WHERE Email = @email", connection);
                    command.Parameters.AddWithValue("@email", email);

                    SqlDataReader reader = command.ExecuteReader();

                    List<User> users = new List<User>();

                    while (reader.Read())
                    {
                        User user = new User
                        {
                            Id = Convert.ToInt32(reader["Id"]),
                            Name = reader["Name"].ToString(),
                            Email = reader["Email"].ToString()
                        };

                        users.Add(user);
                    }

                    return Ok(users);
                }
            }
            catch (Exception ex)
            {
                return StatusCode(500, "An error occurred while searching for users");
            }
        }
    }

    public class User
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Email { get; set; }
    }
